#!/bin/bashset -eecho "=== 瀹為獙1锛歒UM 閰嶇疆鍥藉唴婧?==="BACKUP_DIR="/etc/yum.repos.d/backup-$(date +%Y%m%d)"if [ ! -d "$BACKUP_DIR" ]; then    echo "[1/4] 澶囦唤鍘熸湁 repo 鏂囦欢鍒?$BACKUP_DIR ..."    mkdir -p "$BACKUP_DIR"    cp /etc/yum.repos.d/*.repo "$BACKUP_DIR/" 2>/dev/null || true    echo "  澶囦唤瀹屾垚"else    echo "[1/4] 澶囦唤宸插瓨鍦紝璺宠繃"fiecho "[2/4] 鍐欏叆闃块噷浜戦暅鍍忔簮閰嶇疆 ..."cat > /etc/yum.repos.d/rocky-aliyun.repo << 'EOF'[baseos-aliyun]name=Rocky Linux $releasever - BaseOS (Aliyun)baseurl=https://mirrors.aliyun.com/rockylinux/$releasever/BaseOS/$basearch/os/gpgcheck=1enabled=1gpgkey=file:///etc/pki/rpm-gpg/RPM-GPG-KEY-Rocky-9[appstream-aliyun]name=Rocky Linux $releasever - AppStream (Aliyun)baseurl=https://mirrors.aliyun.com/rockylinux/$releasever/AppStream/$basearch/os/gpgcheck=1enabled=1gpgkey=file:///etc/pki/rpm-gpg/RPM-GPG-KEY-Rocky-9[extras-aliyun]name=Rocky Linux $releasever - Extras (Aliyun)baseurl=https://mirrors.aliyun.com/rockylinux/$releasever/extras/$basearch/os/gpgcheck=1enabled=1gpgkey=file:///etc/pki/rpm-gpg/RPM-GPG-KEY-Rocky-9EOFMV=$(rpm -q rocky-release --qf '%{VERSION}' 2>/dev/null | cut -d. -f1)if [ "$MV" = "9" ]; then    sed -i 's|file:///etc/pki/rpm-gpg/RPM-GPG-KEY-Rocky-9|file:///etc/pki/rpm-gpg/RPM-GPG-KEY-Rocky-9|' /etc/yum.repos.d/rocky-aliyun.repofiecho "[3/4] 娓呯悊缂撳瓨骞堕噸寤?..."yum clean allyum makecacheecho "[4/4] 閰嶇疆瀹屾垚"echo ""echo "=== 瀹為獙1 瀹夎瀹屾垚 ==="